from crewai_tools import BaseTool
from langchain.tools import tool

@tool("validate_source")
def validate_source(url: str) -> str:
    """Validate if research source is accessible and recent"""
    try:
        import requests
        response = requests.head(url, timeout=5)
        if response.status_code == 200:
            return f"✅ VALID: {url} accessible"
        return f"❌ INVALID: {url} returned {response.status_code}"
    except:
        return f"❌ ERROR: {url} unreachable"

