def vex_claim_verification(task_output: str, task: Task):
    """Check claim accuracy against authoritative sources"""
    data = task.json_output
    claims = data.get('key_claims', [])

    verified_claims = []
    for claim in claims:
        verification = vex.verify({
            'type': 'claim_accuracy',
            'claim': claim,
            'context': data.get('sources', []),
            'evidence_required': True,
            'confidence_threshold': 0.8
        })

        if verification['confidence'] > 0.8:
            verified_claims.append({
                'claim': claim,
                'status': 'verified',
                'evidence': verification['evidence']
            })
        else:
            print(f"VEX FLAGGED: {claim} (confidence: {verification['confidence']})")
            return False

    data['verified_claims'] = verified_claims
    return True

